\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:columns {\"isStackedOnMobile\":false,\"className\":\"zunami-history-block__item-content\"} -->\n<div class=\"wp-block-columns is-not-stacked-on-mobile zunami-history-block__item-content\"><!-- wp:column {\"verticalAlignment\":\"center\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\"><!-- wp:heading {\"level\":5} -->\n<h5 class=\"wp-block-heading\">Что сделали</h5>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Запустили инновационный продукт \"страхование рисков срывов сроков доставки в ретейловые сети\"</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":5} -->\n<h5 class=\"wp-block-heading\">Результаты</h5>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>По результатам 2023 года cтраховая премия превысила 37 млн</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:image {\"id\":213,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"https://zunami1.kars-it.ru/wp-content/uploads/2026/01/history-3.webp\" alt=\"\" class=\"wp-image-213\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"className\":\"zunami_visible-lg zunami_non-flex\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group zunami_visible-lg zunami_non-flex\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":3,\"className\":\"animate__animated animate__fadeInUp\"} -->\n<h3 class=\"wp-block-heading has-text-align-center animate__animated animate__fadeInUp\">Блог</h3>\n<!-- /wp:heading -->\n\n<!-- wp:shortcode -->\n[zunami_news class=\"zunami-post-grid_wide\"]\n<!-- /wp:shortcode -->\n\n<!-- wp:html -->\n<div style=\"display: flex; justify-content: center;\"><a href=\"/blog/\" class=\"zunami-button\">Все статьи <span class=\"button-arrow\"></span></a></div>\n<!-- /wp:html --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":3,\"className\":\"animate__animated animate__fadeInUp\"} -->\n<h3 class=\"wp-block-heading has-text-align-center animate__animated animate__fadeInUp\">FAQ</h3>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"className\":\"accordion-group\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group accordion-group\"><!-- wp:accordion {\"headingLevel\":4} -->\n<div role=\"group\" class=\"wp-block-accordion\"><!-- wp:accordion-item -->\n<div class=\"wp-block-accordion-item\"><!-- wp:accordion-heading {\"level\":4} -->\n<h4 class=\"wp-block-accordion-heading\"><button type=\"button\" class=\"wp-block-accordion-heading__toggle\"><span class=\"wp-block-accordion-heading__toggle-title\">В чем отличие страхового брокера от страхового агента?</span><span class=\"wp-block-accordion-heading__toggle-icon\" aria-hidden=\"true\">+</span></button></h4>\n<!-- /wp:accordion-heading -->\n\n<!-- wp:accordion-panel -->\n<div role=\"region\" class=\"wp-block-accordion-panel\"><!-- wp:paragraph -->\n<p>Страховой брокер — юридическое лицо, которое имеет лицензию ЦБ РФ на осуществление деятельности и числится в реестре ЦБ РФ. Брокер действует в интересах клиента, проводит всесторонний анализ рынка с последующим выбором оптимальной программы среди нескольких страховых компаний, в отличие от страхового агента, который представляет конкретную страховую компанию.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:accordion-panel --></div>\n<!-- /wp:accordion-item --></div>\n<!-- /wp:accordion -->\n\n<!-- wp:accordion {\"headingLevel\":4} -->\n<div role=\"group\" class=\"wp-block-accordion\"><!-- wp:accordion-item -->\n<div class=\"wp-block-accordion-item\"><!-- wp:accordion-heading {\"level\":4} -->\n<h4 class=\"wp-block-accordion-heading\"><button type=\"button\" class=\"wp-block-accordion-heading__toggle\"><span class=\"wp-block-accordion-heading__toggle-title\">В каком случае лучше обратиться к страховому брокеру?</span><span class=\"wp-block-accordion-heading__toggle-icon\" aria-hidden=\"true\">+</span></button></h4>\n<!-- /wp:accordion-heading -->\n\n<!-- wp:accordion-panel -->\n<div role=\"region\" class=\"wp-block-accordion-panel\"><!-- wp:paragraph -->\n<p>Если вам необходима комплексная страховка с большим перечнем рисков, но нет времени анализировать и сравнивать предложения страховых компаний.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:accordion-panel --></div>\n<!-- /wp:accordion-item --></div>\n<!-- /wp:accordion -->\n\n<!-- wp:accordion {\"headingLevel\":4} -->\n<div role=\"group\" class=\"wp-block-accordion\"><!-- wp:accordion-item -->\n<div class=\"wp-block-accordion-item\"><!-- wp:accordion-heading {\"level\":4} -->\n<h4 class=\"wp-block-accordion-heading\"><button type=\"button\" class=\"wp-block-accordion-heading__toggle\"><span class=\"wp-block-accordion-heading__toggle-title\">В чем выгода для вас в работе со страховым брокером?</span><span class=\"wp-block-accordion-heading__toggle-icon\" aria-hidden=\"true\">+</span></button></h4>\n<!-- /wp:accordion-heading -->\n\n<!-- wp:accordion-panel -->\n<div role=\"region\" class=\"wp-block-accordion-panel\"><!-- wp:paragraph -->\n<p>Брокер — независимый эксперт, работающий со всеми ключевыми страховыми компаниями. Вы экономите время и получаете наиболее выгодное для вас предложение.<br>Брокер производит оценку рисков клиента и выделяет те, которые более всего нуждаются в хеджировании.<br>Брокер несет полную юридическую ответственность перед страхователем.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:accordion-panel --></div>\n<!-- /wp:accordion-item --></div>\n<!-- /wp:accordion -->\n\n<!-- wp:accordion {\"headingLevel\":4} -->\n<div role=\"group\" class=\"wp-block-accordion\"><!-- wp:accordion-item -->\n<div class=\"wp-block-accordion-item\"><!-- wp:accordion-heading {\"level\":4} -->\n<h4 class=\"wp-block-accordion-heading\"><button type=\"button\" class=\"wp-block-accordion-heading__toggle\"><span class=\"wp-block-accordion-heading__toggle-title\">Как проходит проверка на мошенничество контрагентов?</span><span class=\"wp-block-accordion-heading__toggle-icon\" aria-hidden=\"true\">+</span></button></h4>\n<!-- /wp:accordion-heading -->\n\n<!-- wp:accordion-panel -->\n<div role=\"region\" class=\"wp-block-accordion-panel\"><!-- wp:paragraph -->\n<p>Ключевые процессы брокера построены на основе страховой платформы Zunami, в которой есть функция Антифрод — автоматическое выявление мошенничества при поступлении объектов страхования и претензий.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:accordion-panel --></div>\n<!-- /wp:accordion-item --></div>\n<!-- /wp:accordion -->\n\n<!-- wp:accordion {\"headingLevel\":4} -->\n<div role=\"group\" class=\"wp-block-accordion\"><!-- wp:accordion-item -->\n<div class=\"wp-block-accordion-item\"><!-- wp:accordion-heading {\"level\":4} -->\n<h4 class=\"wp-block-accordion-heading\"><button type=\"button\" class=\"wp-block-accordion-heading__toggle\"><span class=\"wp-block-accordion-heading__toggle-title\">Почему я могу доверять страховому брокеру?</span><span class=\"wp-block-accordion-heading__toggle-icon\" aria-hidden=\"true\">+</span></button></h4>\n<!-- /wp:accordion-heading -->\n\n<!-- wp:accordion-panel -->\n<div role=\"region\" class=\"wp-block-accordion-panel\"><!-- wp:paragraph -->\n<p>Во-первых, страховой брокер имеет лицензию и числится в реестре ЦБ РФ, а денежные средства, перечисляемые брокеру в счет оплаты страхового полиса хранятся на специальном счете и не могут быть использованы по иному назначению.<br>Также страховой брокер имеет гарантийный депозит в размере 3 млн рублей, обеспечивающий сохранность средств клиентов.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:accordion-panel --></div>\n<!-- /wp:accordion-item --></div>\n<!-- /wp:accordion --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:columns {\"className\":\"contact-form-block pad-top-lg\"} -->\n<div class=\"wp-block-columns contact-form-block pad-top-lg\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Eсли у вас остались <br>вопросы — напишите нам</h3>\n<!-- /wp:heading --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:contact-form-7/contact-form-selector {\"id\":216,\"hash\":\"66f805d\",\"title\":\"Обратная связь\"} -->\n<div class=\"wp-block-contact-form-7-contact-form-selector\">[contact-form-7 id=\"66f805d\" title=\"Обратная связь\"]</div>\n<!-- /wp:contact-form-7/contact-form-selector --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Zunami страховой брокер','','publish','closed','closed','','home','','','2026-03-02 02:31:57','2026-03-01 23:31:57','',0,'https://zunami1.kars-it.ru/?page_id=70',10,'page','',0);
INSERT INTO `SERVMASK_PREFIX_posts` VALUES (75,2,'2025-12-03 19:29:08','2025-12-03 16:29:08','<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column {\"verticalAlignment\":\"center\",\"className\":\"zunami_lg-grow-7\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center zunami_lg-grow-7\"><!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">Брокер&nbsp;<em>Zunami</em>&nbsp;— профессиональный участник страхового рынка, предоставляющий полный спектр страховых услуг в сфере логистики</h1>\n<!-- /wp:heading --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"className\":\"zunami_lg-grow-5\"} -->\n<div class=\"wp-block-column zunami_lg-grow-5\"><!-- wp:image {\"id\":135,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"https://zunami1.kars-it.ru/wp-content/uploads/2026/01/company-banner.webp\" alt=\"\" class=\"wp-image-135\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:group {\"className\":\"tops-block pad-bottom-lg pad-top-md\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group tops-block pad-bottom-lg pad-top-md\"><!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":4} -->\n<h4 class=\"wp-block-heading has-text-align-center\">ТОП-[countdown from=\"9\" to=\"5\"]</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">по страхованию грузов</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"className\":\"tops-col-bordered\"} -->\n<div class=\"wp-block-column tops-col-bordered\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":4} -->\n<h4 class=\"wp-block-heading has-text-align-center\">[countdown from=\"1\" to=\"120\" after=\"+\"] млн</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">страховая премия</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"textAlign\":\"center\",\"level\":4} -->\n<h4 class=\"wp-block-heading has-text-align-center\">[countdown from=\"1\" to=\"3\" after=\"+\"] лет</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\">срок действия наших <br>договоров страхования</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:group -->\n\n<!-- wp:shortcode -->\n[zunami_hblock caption=\"Свидетельство АПСБ № 083<br>от 13.09.2019 (Член)\" url=\"/licenses/\" text=\"Член Ассоциации профессиональных страховых брокеров\"]\n<!-- /wp:shortcode -->\n\n<!-- wp:shortcode -->\n[zunami_hblock caption=\"Профессиональный страховой брокер<br>(лицензия ЦБ РФ №СБ 4369 от 11.07.2022)\" url=\"/licenses/\" button=\"Скачать документ в PDF\" href=\"/wp-content/uploads/2026/01/ЭП_4369.pdf\"]\n<!-- /wp:shortcode -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":5,\"className\":\"pad-top-xl pad-bottom-md\"} -->\n<h5 class=\"wp-block-heading has-text-align-center pad-top-xl pad-bottom-md\">Информация о наличии или об отсутствии участия в капитале страховщика (страховщиков):</h5>\n<!-- /wp:heading -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>доля участия страховщика (страховщиков) в капитале ООО «Страховой брокер \"Цунами\"»:&nbsp;<span class=\"color-alt\">отсутствует</span></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>доля участия ООО «Страховой брокер \"Цунами\"» в капитале страховщика (страховщиков):&nbsp;<span class=\"color-alt\">отсутствует</span></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','О компании','','publish','closed','closed','','company','','','2026-03-02 06:34:39','2026-03-02 03:34:39','',0,'https://zunami1.kars-it.ru/?page_id=75',20,'page','',0);
INSERT INTO `SERVMASK_PREFIX_posts` VALUES (77,2,'2025-12-03 19:29:26','2025-12-03 16:29:26','<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:shortcode -->\n[zunami_iconbox href=\"#main_popup\" title=\"Страхование селлеров маркетплейсов\" text=\"Защитите свои товары от финансовых и имущественных рисков\" button=\"Получить предложение\" icon=\"/wp-content/uploads/2026/01/icon-seller-ins.svg\"]\n<!-- /wp:shortcode --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:shortcode -->\n[zunami_iconbox href=\"#main_popup\" title=\"Страхование ответственности экспедитора (перевозчика)\" text=\"Защититесь от убытков, связанных с возможными ошибками или недочётами в работе\" button=\"Получить предложение\" icon=\"/wp-content/uploads/2026/01/icon-exp-ins.svg\"]\n<!-- /wp:shortcode --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:shortcode -->\n[zunami_iconbox href=\"#main_popup\" title=\"Страхование грузов\" text=\"Защитите свои грузы от возможных убытков и непредвиденных расходов при транспортировке\" button=\"Получить предложение\" icon=\"/wp-content/uploads/2026/01/icon-cargo-ins.svg\"]\n<!-- /wp:shortcode --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:shortcode -->\n[zunami_iconbox href=\"#main_popup\" title=\"Страхование торговых кредитов\" text=\"Защитите свою компанию от рисков неплатежей или банкротства ваших контрагентов\" button=\"Получить предложение\" icon=\"/wp-content/uploads/2026/01/icon-credit-ins.svg\"]\n<!-- /wp:shortcode --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:shortcode -->\n[zunami_iconbox href=\"#main_popup\" title=\"Страхование сроков доставки и ретейловых штрафов\" text=\"Защититесь от убытков, связанных с задержкой доставки товаров и возможными штрафами за нарушение сроков поставки\" button=\"Получить предложение\" icon=\"/wp-content/uploads/2026/01/icon-terms-ins.svg\"]\n<!-- /wp:shortcode --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:shortcode -->\n[zunami_iconbox href=\"#main_popup\" title=\"Страхование КАСКО и ОСАГО\" text=\"Защитите ваш автопарк от повреждений, угона, а также от причинения вреда другим участниками дорожного движения в случае ДТП\" button=\"Получить предложение\" icon=\"/wp-content/uploads/2026/01/icon-osago-ins.svg\"]\n<!-- /wp:shortcode --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns {\"className\":\"pad-top-md\"} -->\n<div class=\"wp-block-columns pad-top-md\"><!-- wp:column {\"className\":\"zunami-block pad-top-md pad-bottom-lg\"} -->\n<div class=\"wp-block-column zunami-block pad-top-md pad-bottom-lg\"><!-- wp:image {\"id\":143,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"image-rounded\"} -->\n<figure class=\"wp-block-image size-full image-rounded\"><img src=\"https://zunami1.kars-it.ru/wp-content/uploads/2026/01/uslugi-1.webp\" alt=\"\" class=\"wp-image-143\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"textAlign\":\"left\",\"level\":4,\"className\":\"pad-top-sm pad-bottom-sm\"} -->\n<h4 class=\"wp-block-heading has-text-align-left pad-top-sm pad-bottom-sm\">Страховщикам:</h4>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"className\":\"fs-md\"} -->\n<ul class=\"wp-block-list fs-md\"><!-- wp:list-item -->\n<li>Совершение в интересах клиента-страхователя операций, связанных с заключением договора страхования</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Разработка программы страховой защиты на основе анализа потребностей клиента</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Подготовка и согласование условий страхования (согласование формы договора, рисков, исключений, порядка исполнения)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Сопровождение договора страхования (анализ изменения степени риска, урегулирование убытков)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Представление интересов страховщика при реализации последним права суброгации или права на регрессные иски</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"className\":\"zunami-block\"} -->\n<div class=\"wp-block-column zunami-block\"><!-- wp:image {\"id\":144,\"sizeSlug\":\"full\",\"linkDestination\":\"none\",\"className\":\"image-rounded\"} -->\n<figure class=\"wp-block-image size-full image-rounded\"><img src=\"https://zunami1.kars-it.ru/wp-content/uploads/2026/01/uslugi-2.webp\" alt=\"\" class=\"wp-image-144\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"textAlign\":\"left\",\"level\":4,\"className\":\"pad-top-sm pad-bottom-sm\"} -->\n<h4 class=\"wp-block-heading has-text-align-left pad-top-sm pad-bottom-sm\">Страхователям:</h4>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"className\":\"fs-md\"} -->\n<ul class=\"wp-block-list fs-md\"><!-- wp:list-item -->\n<li>Организация процесса совместного страхования риска несколькими страховщиками</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Осуществление экспертного андеррайтинга</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Участие в разработке правил страхования, страховых программ, экономического обоснования деятельности страховщиков</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:paragraph {\"className\":\"fw-500 fs-lg pad-top-xl\"} -->\n<p class=\"fw-500 fs-lg pad-top-xl\">Результаты анализа страховых услуг (подлежащих страхованию объектов, страховых рисков, страховых тарифов и иных условий страхования у различных страховщиков) предоставляются страхователю по его требованию</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"color-alt\"} -->\n<p class=\"color-alt\">Компания не оказывает посреднических услуг по страхованию физическим лицам</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"pad-top-xl\"} -->\n<p class=\"pad-top-xl\"></p>\n<!-- /wp:paragraph -->','Услуги','','publish','closed','closed','','uslugi','','','2026-03-02 03:26:47','2026-03-02 00:26:47','',0,'https://zunami1.kars-it.ru/?page_id=77',30,'page','',0);
INSERT INTO `SERVMASK_PREFIX_posts` VALUES (79,2,'2025-12-03 19:29:53','2025-12-03 16:29:53','<!-- wp:heading {\"textAlign\":\"center\",\"level\":3} -->\n<h3 class=\"wp-block-heading has-text-align-center\">Контроль и надзор за деятельностью страховых брокеров осуществляется Центральным Банком Российской Федерации</h3>\n<!-- /wp:heading -->\n\n<!-- wp:image {\"lightbox\":{\"enabled\":false},\"id\":163,\"sizeSlug\":\"large\",\"linkDestination\":\"custom\",\"align\":\"center\"} -->\n<figure class=\"wp-block-image aligncenter size-large\"><a href=\"https://cbr.ru/\"><img src=\"https://zunami1.kars-it.ru/wp-content/uploads/2026/01/zb_logo_blue.svg\" alt=\"\" class=\"wp-image-163\"/></a></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\"><a href=\"https://cbr.ru/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\" class=\"intext-link\">сайт www.cbr.ru</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"textAlign\":\"center\",\"level\":3} -->\n<h3 class=\"wp-block-heading has-text-align-center\">Сведения о способах и адресах для направления обращений получателей страховых услуг представлены на следующих сайтах:</h3>\n<!-- /wp:heading -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:group {\"className\":\"zunami-block\",\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group zunami-block\"><!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column {\"width\":\"33.33%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:33.33%\"><!-- wp:image {\"id\":404,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"https://zunami1.kars-it.ru/wp-content/uploads/2026/03/insbrocker.webp\" alt=\"Ассоциация профессиональных страховых брокеров\" class=\"wp-image-404\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"width\":\"66.66%\"} 