INSERT INTO `SERVMASK_PREFIX_posts` VALUES (83,2,'2025-12-03 19:30:53','2025-12-03 16:30:53','<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column {\"className\":\"flex-2-xl\"} -->\n<div class=\"wp-block-column flex-2-xl\"><!-- wp:columns {\"className\":\"flex-col-lg\"} -->\n<div class=\"wp-block-columns flex-col-lg\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"level\":5} -->\n<h5 class=\"wp-block-heading\">Позвоните или напишите нам:</h5>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Телефон: <a href=\"tel:+74012391938\">+7 (4012) 39-19-38</a><br>Почта: <a href=\"mailto:info@zunami.pro\">info@zunami.pro</a></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"level\":5} -->\n<h5 class=\"wp-block-heading\">Центральный офис:</h5>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>236040, Калининградская обл.,<br>г. о. город Калининград,<br>г. Калининград, пл. Победы, д. 10, офис 518А</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":5} -->\n<h5 class=\"wp-block-heading\">Режим работы:</h5>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Пн—Пт: с 10:00 до 19:00<br>по московскому времени<br>Перерыв: с 13:00 до 14:00</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"level\":5} -->\n<h5 class=\"wp-block-heading\">Отправьте заявку, мы обязательно свяжемся с вами:</h5>\n<!-- /wp:heading -->\n\n<!-- wp:contact-form-7/contact-form-selector {\"id\":253,\"hash\":\"14d2396\",\"title\":\"Заявка (контакты)\"} -->\n<div class=\"wp-block-contact-form-7-contact-form-selector\">[contact-form-7 id=\"14d2396\" title=\"Заявка (контакты)\"]</div>\n<!-- /wp:contact-form-7/contact-form-selector --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:shortcode -->\n[ya-map apikey=\"41e18f86-f42e-41a6-a239-308f4150097