INSERT INTO `SERVMASK_PREFIX_posts` VALUES (119,2,'2026-01-14 02:09:05','2026-01-13 23:09:05','<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\"><a href=\"/wp-content/uploads/2026/03/Спец.оценка.pdf\" target=\"_blank\" rel=\"noreferrer noopener\" class=\"zunami-button zunami-button_simple\">Отчет о проведении специальной оценки труда</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\"><a href=\"/wp-content/uploads/2026/03/Спец_оценка_27_11_2020.pdf\" target=\"_blank\" rel=\"noreferrer noopener\" class=\"zunami-button zunami-button_simple\">Отчет о проведении специальной оценки труда</a></p>\n<!-- /wp:paragraph -->','Информация по охране труда','','publish','closed','closed','','informatsiya-po-okhrane-truda','','','2026-03-02 08:51:08','2026-03-02 05:51:08','',0,'https://zunami1.kars-it.ru/?page_id=119',54,'page','',0);
INSERT INTO `SERVMASK_PREFIX_posts` VALUES (121,2,'2026-01-14 02:09:43','2026-01-13 23:09:43','<!-- wp:paragraph -->\n<p>Настоящим&nbsp;я, во&nbsp;исполнение требований Федерального закона от&nbsp;27.07.2006 №&nbsp;152-ФЗ «О&nbsp;персональных данных», Федерального закона от&nbsp;13.03.2006 №&nbsp;38-ФЗ «О&nbsp;рекламе», действуя по&nbsp;своей воле и&nbsp;в&nbsp;своем интересе, даю согласие&nbsp;ООО «Страховой брокер «Цунами»» (236040, Калининградская область, г.о. город Калининград, г. Калининград, площадь Победы, д. 10, офис 518А) (далее&nbsp;— Компания) на&nbsp;обработку своих персональных данных, указанных при регистрации, подписке на&nbsp;рассылки, оставлении заявки, заполненной в&nbsp;веб-форме на&nbsp;сайте Компании и&nbsp;направленной с&nbsp;использованием Сайта с целью взаимодействия и получения услуг, оказываемых Компанией.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Под персональными данными понимается любая информация, относящаяся к прямо или косвенно определенному или определяемому физическому лицу (субъекту персональных данных).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Категории и перечень персональных данных, разрешенных мною</strong><br><strong>для обработки:</strong><br>· фамилия, имя, отчество;<br>·&nbsp;наименование организации;<br>·&nbsp;номер мобильного телефона;<br>·&nbsp;адрес электронной почты (e-mail);<br>· сведения, собираемые посредством метрических программ;<br>·&nbsp;иная информация, которую предоставит субъект персональных данных.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Принятием (акцептом) согласия является проставление отметки в поле формы, сопровождаемом текстом «Я даю Согласие на обработку персональных данных в соответствии с Политикой обработки и обеспечения безопасности персональных данных» на сайте Компании.<br>Настоящее согласие дается на осуществление следующих действий в отношении моих персональных данных: сбор, запись, систематизацию, накопление, хранение, уточнение (обновление, изменение), извлечение, использование, передачу (распространение, предоставление, доступ), обезличивание, блокирование, удаление, уничтожение.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Согласие дано с правом передачи Компанией моих персональных данных:<br>·&nbsp;ООО «ЯНДЕКС» (г. Москва, ул. Льва Толстого, д. 16) и его аффилированным лицам, в том числе входящих в одну группу с ООО «ЯНДЕКС»;<br>·&nbsp;ООО «Инносети» (236016, Россия, Калининградская обл., город Калининград г.о., г. Калининград, ул. Фрунзе, д. 51, пом. 26, ОГРН 1185024002723, ИНН/ КПП 5024182694/ 390601001) в случае осуществления технической поддержки;<br>·&nbsp;третьим лицам, сведения о которых будут размещены на информационном (рекламном) ресурсе, информационном (рекламном) материале, включая рекламные лендинги, сообщения об акциях и иных мероприятиях Компании, через которые я передаю свои персональные данные.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Согласие на обработку данных, собираемых посредством метрических программ, дается с целью функционирования сайта и проведения статистических исследований путем нажатия пользователем кнопки&nbsp;«ОК»<strong>&nbsp;</strong>рядом с текстом: «Оставаясь на сайте Вы выражаете своё согласие на обработку персональных данных, собираемых посредством сервиса «Яндекс.Метрика» и на использование файлов cookie в соответствии с Политикой обработки персональных данных.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>В случае несогласия Вы можете покинуть страницу или отключить сохранение cookie в параметрах настройки вашего браузера».</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Я проинформирован(а), что Компания гарантирует обработку моих персональных данных в соответствии с действующим законодательством Российской Федерации как автоматизированным, так и неавтоматизированным способами.<br>Об ответственности за достоверность предоставленных сведений предупрежден(а).<br>Согласие действует со дня его подписания и до момента достижения цели.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Настоящее согласие может быть отозвано мною в любое время путем направления письменного уведомления на адрес: 236040, Калининградская область, г.о. город Калининград, г. Калининград, площадь Победы, дом 10, офис 518А «отзыв согласия на обработку персональных данных».<br>Я&nbsp;обязуюсь незамедлительно сообщать Компании об&nbsp;изменении моих персональных данных, сведений обо мне с&nbsp;предоставлением подтверждающих документов.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Настоящим Согласием я&nbsp;подтверждаю, что являюсь субъектом предоставляемых персональных данных, а&nbsp;также что эти данные достоверны. В случае предоставления мной данных третьих лиц, включая контактные данные, я подтверждаю, что субъект персональных данных уведомлен об осуществлении обработки его персональных данных Компанией.<br>Удаление персональных данных будет произведено Компанией в течение 30 дней с момента получения данного уведомления, если иной срок не предусмотрен действующим законодательством. В соответствии с Федеральным законом от 27.07.2006 № 152-ФЗ «О персональных данных» случаях Компания будет вправе продолжать осуществлять обработку персональных данных в отсутствии согласия.</p>\n<!-- /wp:paragraph -->','Согласие на обработку персональных данных','','publish','closed','closed','','approval','','','2026-01-20 07:58:02','2026-01-20 04:58:02','',0,'https://zunami1.kars-it.ru/?page_id=121',92,'page','',0);
INSERT INTO `SERVMASK_PREFIX_posts` VALUES (123,2,'2026-01-14 02:10:10','2026-01-13 23:10:10','<!-- wp:paragraph -->\n<p>В соответствии с Федеральным законом от 13.03.2006 № 38-ФЗ «О рекламе» и Федеральным законом от 07.07.2003 № 126-ФЗ «О связи» настоящим я, действуя по своей воле и в своем интересе, даю ООО «Страховой брокер «Цунами»» (236040, Калининградская область, г.о. город Калининград, г. Калининград, площадь Победы, дом 10, офис 518А) (далее&nbsp;— Компания) согласие на направление мне сообщений о программных продуктах, услугах (сервисах) Компании и (или) аффилированных лиц в информационных, рекламно-информационных целях. К таким сообщениям относятся рассылки о мероприятиях, контенте, акциях, другие не запрещенные законодательством текстовые, сообщения информационного и рекламного характера. Для отправки будут использоваться указанные мной на сайте&nbsp;<a href=\"https://zunami1.kars-it.ru/\">https://zunami1.kars-it.ru/</a>&nbsp;контактные данные (номер телефона, адрес электронной почты). Информация направляется в виде СМС-сообщений, электронных писем, push-уведомлений.<br>Я согласен(а) с тем, что текст согласия, данного мной по собственной воле и в моих интересах, хранится в электронном виде в базе данных Компании и подтверждает мою готовность получать материалы в соответствии с вышеизложенными положениями. Я беру на себя ответственность за достоверность предоставленных данных.<br>Я проинформирован(а), что в любой момент в течение срока действия настоящего согласия я вправе отозвать согласие и отписаться от получения рассылок, перейдя по ссылке в любом письме.<br>Согласие действует со дня его подписания и в течение 10 лет.<br>Настоящим подтверждаю, что мои конклюдентные действия (проставление отметки в поле формы, сопровождаемом текстом «Я даю согласие на получение рекламной и информационной рассылки») на сайте&nbsp;<a href=\"https://zunami1.kars-it.ru/\">https://zunami1.kars-it.ru/</a>&nbsp;являются достаточной формой согласия и позволяют подтвердить сторонам факт получения такого согласия. При этом иных доказательств для подтверждения моего свободного волеизъявления не потребуется.</p>\n<!-- /wp:paragraph -->','Согласие на получение рекламной рассылки','','publish','closed','closed','','addapproval','','','2026-01-20 07:59:54','2026-01-20 04:59:54','',0,'https://zunami1.kars-it.ru/?page_id=123',94,'page','',0);
INSERT INTO `SERVMASK_PREFIX_posts` VALUES (125,2,'2026-01-14 02:10:34','2026-01-13 23:10:34','<!-- wp:columns {\"verticalAlignment\":null} -->\n<div class=\"wp-block-columns\"><!-- wp:column {\"verticalAlignment\":\"center\",\"width\":\"33.33%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-center\" style=\"flex-basis:33.33%\"><!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">Спасибо</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Ваша заявка<br>успешно отправлена.<br>Скоро мы свяжемся с вами</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:html -->\n<a href=\"/\" class=\"zunami-button\">На главную</a>\n<!-- /wp:html --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"width\":\"66.66%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:66.66%\"><!-- wp:image {\"id\":272,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"https://zunami1.kars-it.ru/wp-content/uploads/2026/01/thx-1024x598.webp\" alt=\"\" class=\"wp-image-272\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->','Ваша заявка отправлена','','publish','closed','closed','','successfully','','','2026-02-25 17:05:58','2026-02-25 14:05:58','',0,'https://zunami1.kars-it.ru/?page_id=125',96,'page','',0);
