INSERT INTO `SERVMASK_PREFIX_posts` VALUES (216,2,'2026-01-20 01:14:24','2026-01-19 22:14:24','<div class=\"form-field\">\r\n[text* your-name autocomplete:name placeholder \"Имя\"]\r\n</div>\r\n<div class=\"form-field\">\r\n[tel* your-tel placeholder \"+7 (000) 000-00-00\"]\r\n</div>\r\n<div class=\"form-field\">\r\n[email* your-email autocomplete:email placeholder \"email\"]\r\n</div>\r\n<div class=\"form-field\">\r\n[text your-business placeholder \"Вид бизнеса\"]\r\n</div>\r\n<div class=\"form-field\">\r\n[textarea* your-message placeholder \"Ваш вопрос\"]\r\n</div>\r\n<div class=\"form-field form-field_acceptance\">\r\n[acceptance acceptance-pd] Я даю <a href=\"/approval\">согласие</a> на обработку персональных данных в соответствии с <a href=\"/politica\">Политикой обработки и обеспечения безопасности персональных данных</a> [/acceptance]\r\n</div>\r\n<div class=\"form-field form-field_acceptance\">\r\n[acceptance acceptance-ad] Я даю <a href=\"/addapproval\">согласие</a> на получение рекламной и информационной рассылки [/acceptance]\r\n</div>\r\n<button class=\"zunami-button\">Отправить <span class=\"button-arrow\"></span></button>\n1\n[_site_title] Обратная связь\n[_site_title] <wordpress@zunami.pro>\nsbalyberdin@gmail.com\nИмя: [your-name]\r\nТелефон: [your-tel]\r\nПочта: [your-email]\r\nВид бизнеса: [your-business]\r\nСообщение: [your-message]\nReply-To: [your-email]\n\n1\n1\n\n[_site_title] \"[your-subject]\"\n[_site_title] <wordpress@zunami.pro>\n[your-email]\nСообщение:\r\n[your-message]\r\n\r\n-- \r\nЭто письмо является квитанцией об отправке контактной формы на нашем веб-сайте ([_site_title] [_site_url]), в которой использовался ваш адрес электронной почты. Если это были не вы, пожалуйста, проигнорируйте это сообщение.\nReply-To: [_site_admin_email]\n\n1\n1\nСпасибо за Ваше сообщение. Оно успешно отправлено.\nПри отправке сообщения произошла ошибка. Пожалуйста, попробуйте ещё раз позже.\nОдно или несколько полей содержат ошибочные данные. Пожалуйста, проверьте их и попробуйте ещё раз.\nПри отправке сообщения произошла ошибка. Пожалуйста, попробуйте ещё раз позже.\nВы должны принять условия и положения перед отправкой вашего сообщения.\nВажно заполнить это поле.\nВ это поле вставлен слишком большой объем данных.\nВ это поле вставлен слишком малый объем данных.\nПри загрузке файла произошла неизвестная ошибка.\nВам не разрешено загружать файлы этого типа.\nЗагруженный файл слишком большой.\nПри загрузке файла произошла ошибка.\nВведите дату в формате ГГГГ-ММ-ДД.\nВ это поле введена слишком ранняя дата.\nВ это поле введена слишком поздняя дата.\nВведите число.\nВ это поле введено слишком маленькое число.\nВ это поле введено слишком большое число.\nНеверный ответ на проверочный вопрос.\nВведите адрес электронной почты.\nВведите URL.\nВведите номер телефона.','Обратная связь','','publish','closed','closed','','%d0%be%d0%b1%d1%80%d0%b0%d1%82%d0%bd%d0%b0%d1%8f-%d1%81%d0%b2%d1%8f%d0%b7%d1%82','','','2026-03-02 11:08:41','2026-03-02 08:08:41','',0,'https://zunami1.kars-it.ru/?post_type=wpcf7_contact_form&#038;p=216',0,'wpcf7_contact_form','',0);
